def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    mapping = {
        3: 4,
        1: 5,
        2: 6,
        4: 3,
        8: 9,
        6: 2,
        9: 8,
        5: 1,
    }
    return np.vectorize(lambda x: mapping.get(int(x), int(x)))(input_grid)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, dtype=int)
    h, w = g.shape

    # Find the smallest repeating period in rows and columns by comparing
    # non-black structure across the grid.
    def find_period(arr, axis):
        n = arr.shape[axis]
        for p in range(1, n + 1):
            ok = True
            for i in range(n):
                j = i % p
                if axis == 0:
                    a = arr[i, :]
                    b = arr[j, :]
                else:
                    a = arr[:, i]
                    b = arr[:, j]
                # Periodic pattern may have black erasures; compare only where both are nonzero
                mask = (a != 0) & (b != 0)
                if np.any(a[mask] != b[mask]):
                    ok = False
                    break
            if ok:
                return p
        return n

    pr = find_period(g, 0)
    pc = find_period(g, 1)

    # Reconstruct the full periodic grid by taking the first observed nonzero
    # value for each residue class modulo the period.
    template = np.zeros((pr, pc), dtype=int)
    for r in range(h):
        for c in range(w):
            v = g[r, c]
            if v != 0:
                template[r % pr, c % pc] = v

    out = np.empty_like(g)
    for r in range(h):
        for c in range(w):
            out[r, c] = template[r % pr, c % pc]
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the separator row: the row containing the most non-zero cells.
    nonzero_counts = np.count_nonzero(grid, axis=1)
    sep_row = int(np.argmax(nonzero_counts))
    sep_color = int(grid[sep_row][grid[sep_row] != 0][0]) if nonzero_counts[sep_row] > 0 else 0

    out = np.zeros_like(grid)
    out[sep_row, :] = sep_color

    # For each marker cell, extend it based on its position relative to separator.
    for r in range(h):
        for c in range(w):
            val = int(grid[r, c])
            if val == 0:
                continue
            if r == sep_row:
                continue
            if r < sep_row:
                out[r, :] = val
            else:
                out[:, c] = val

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, dtype=int)
    n, m = grid.shape
    out = np.zeros((n, m), dtype=int)

    vals, counts = np.unique(grid[grid != 0], return_counts=True)
    if len(vals) == 0:
        return out
    color = int(vals[np.argmax(counts)])

    coords = np.argwhere(grid == color)
    if coords.size == 0:
        return out

    # Determine diagonal type from the colored cells in the 2x2 pattern
    rs = coords[:, 0]
    cs = coords[:, 1]
    if np.any((rs - cs) == (rs[0] - cs[0])) and len(coords) >= 2:
        diag_type = "main"
    elif np.any((rs + cs) == (rs[0] + cs[0])) and len(coords) >= 2:
        diag_type = "anti"
    else:
        # Fallback: infer from the arrangement of the non-black cells
        diag_type = "main" if len(np.unique(rs - cs)) <= len(np.unique(rs + cs)) else "anti"

    for i in range(n):
        for j in range(m):
            if diag_type == "main":
                if abs(i - j) <= 2:
                    out[i, j] = color
            else:
                if abs((i + j) - (m - 1)) <= 2:
                    out[i, j] = color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    rows, cols = grid.shape

    divider_row = None
    for r in range(rows):
        if np.any(grid[r] == 4):
            divider_row = r
            break

    if divider_row is None:
        return np.zeros((4, 4), dtype=int)

    top = grid[:divider_row]
    bottom = grid[divider_row + 1:]

    def bbox_of_nonzero(arr):
        pts = np.argwhere(arr != 0)
        if pts.size == 0:
            return None
        r0, c0 = pts.min(axis=0)
        r1, c1 = pts.max(axis=0)
        return r0, r1, c0, c1

    b1 = bbox_of_nonzero(top)
    b2 = bbox_of_nonzero(bottom)

    if b1 is None or b2 is None:
        return np.zeros((4, 4), dtype=int)

    r0 = min(b1[0], b2[0])
    r1 = max(b1[1], b2[1])
    c0 = min(b1[2], b2[2])
    c1 = max(b1[3], b2[3])

    h = r1 - r0 + 1
    w = c1 - c0 + 1

    top_crop = top[r0:r1 + 1, c0:c1 + 1]
    bottom_crop = bottom[r0:r1 + 1, c0:c1 + 1]

    out = np.zeros((h, w), dtype=int)
    for i in range(h):
        for j in range(w):
            a = top_crop[i, j] != 0
            b = bottom_crop[i, j] != 0
            if a ^ b:
                out[i, j] = 3

    return out

