def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    h, w = input_grid.shape
    output = np.zeros_like(input_grid)
    for c in range(w):
        rows = np.where(input_grid[:, c] != 0)[0]
        for r in rows:
            nr = r + c
            if nr < h:
                output[nr, c] = input_grid[r, c]
    return output

