def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    color = 8
    fill = 3

    # Horizontal connections
    for r in range(h):
        cols = np.where(grid[r] == color)[0]
        if len(cols) >= 2:
            for c1, c2 in zip(cols[:-1], cols[1:]):
                if c2 > c1 + 1:
                    grid[r, c1 + 1:c2] = fill

    # Vertical connections
    for c in range(w):
        rows = np.where(grid[:, c] == color)[0]
        if len(rows) >= 2:
            for r1, r2 in zip(rows[:-1], rows[1:]):
                if r2 > r1 + 1:
                    grid[r1 + 1:r2, c] = fill

    return grid

