import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find all non-zero cells that are not part of the common frame color 1
    # These are seed cells inside 5x5 motifs.
    seeds = np.argwhere((grid != 0) & (grid != 1))

    for r, c in seeds:
        color = grid[r, c]

        # Motif is a 5x5 frame with seed at center: top-left = (r-2, c-2)
        r0, c0 = r - 2, c - 2
        if r0 < 0 or c0 < 0 or r0 + 4 >= h or c0 + 4 >= w:
            continue

        # Fill top border row of the 5x5 motif
        for cc in range(c0, c0 + 5):
            if grid[r0, cc] == 0:
                grid[r0, cc] = color

        # Fill the 3x3 inner square, excluding side borders (left/right columns)
        for rr in range(r0 + 1, r0 + 4):
            for cc in range(c0 + 1, c0 + 4):
                if grid[rr, cc] == 0:
                    grid[rr, cc] = color

    return grid

