def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    seen = set()
    order = []
    for v in input_grid.flatten():
        if v != 0 and v not in seen:
            seen.add(int(v))
            order.append(int(v))
    return np.array(order, dtype=int).reshape(-1, 1)

