def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = grid.copy()

    for r in range(h - 1):
        for c in range(w - 1):
            block = grid[r:r+2, c:c+2]
            vals = block.flatten()
            nonzero = vals[vals != 0]
            if nonzero.size == 4 and np.all(nonzero == nonzero[0]):
                out[r:r+2, c:c+2] = 4
    return out

