def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    out = np.array(grid, copy=True)
    h, w = grid.shape
    color = 4

    # Find connected components of the target color
    visited = np.zeros((h, w), dtype=bool)
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for r in range(h):
        for c in range(w):
            if grid[r, c] != color or visited[r, c]:
                continue

            # BFS/DFS for one component
            stack = [(r, c)]
            visited[r, c] = True
            comp = []
            while stack:
                x, y = stack.pop()
                comp.append((x, y))
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                        visited[nx, ny] = True
                        stack.append((nx, ny))

            comp_set = set(comp)

            # For each black cell orthogonally adjacent to at least two cells in this component,
            # recolor it orange.
            candidates = {}
            for x, y in comp:
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and grid[nx, ny] == 0 and (nx, ny) not in comp_set:
                        candidates[(nx, ny)] = candidates.get((nx, ny), 0) + 1

            for (x, y), cnt in candidates.items():
                if cnt >= 2:
                    out[x, y] = 7

    return out

