def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    rows, cols = grid.shape

    # Find horizontal divider rows: rows filled entirely with 8
    divider_rows = [r for r in range(rows) if np.all(grid[r] == 8)]
    if len(divider_rows) < 2:
        return np.zeros((3, 3), dtype=int)

    r1, r2 = divider_rows[0], divider_rows[1]

    # Find vertical divider columns: columns filled entirely with 8
    divider_cols = [c for c in range(cols) if np.all(grid[:, c] == 8)]
    if len(divider_cols) < 2:
        return np.zeros((3, 3), dtype=int)

    c1, c2 = divider_cols[0], divider_cols[1]

    top = grid[:r1, :c1]
    bottom = grid[r1 + 1:r2, :c1]

    # If the regions are not 3x3, try using the first 3 rows/cols of each region
    top = top[:3, :3]
    bottom = bottom[:3, :3]

    out = np.zeros((3, 3), dtype=int)
    for i in range(3):
        for j in range(3):
            if top[i, j] != 0 and bottom[i, j] == 0:
                out[i, j] = 1
    return out

