import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    def components(color):
        visited = np.zeros((h, w), dtype=bool)
        comps = []
        for r in range(h):
            for c in range(w):
                if grid[r, c] == color and not visited[r, c]:
                    stack = [(r, c)]
                    visited[r, c] = True
                    cells = []
                    while stack:
                        x, y = stack.pop()
                        cells.append((x, y))
                        for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                                visited[nx, ny] = True
                                stack.append((nx, ny))
                    comps.append(cells)
        return comps

    def norm_shape(cells):
        rs = [r for r, c in cells]
        cs = [c for r, c in cells]
        r0, c0 = min(rs), min(cs)
        pts = sorted((r - r0, c - c0) for r, c in cells)
        return tuple(pts)

    color_comps = {}
    for color in [1, 2, 3, 5]:
        comps = components(color)
        color_comps[color] = [(cells, norm_shape(cells)) for cells in comps]

    shape_to_colors = {}
    for color, comps in color_comps.items():
        for cells, shp in comps:
            shape_to_colors.setdefault(shp, set()).add(color)

    out = np.array(grid, copy=True)
    for color, comps in color_comps.items():
        for cells, shp in comps:
            if len(shape_to_colors.get(shp, set())) > 1:
                for r, c in cells:
                    out[r, c] = 3
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    zero_rows = np.where(np.all(g == 0, axis=1))[0]
    zero_cols = np.where(np.all(g == 0, axis=0))[0]

    row_breaks = [-1] + zero_rows.tolist() + [h]
    col_breaks = [-1] + zero_cols.tolist() + [w]

    row_blocks = []
    for i in range(len(row_breaks) - 1):
        a, b = row_breaks[i] + 1, row_breaks[i + 1]
        if a < b:
            row_blocks.append((a, b))

    col_blocks = []
    for i in range(len(col_breaks) - 1):
        a, b = col_breaks[i] + 1, col_breaks[i + 1]
        if a < b:
            col_blocks.append((a, b))

    out = np.zeros((len(row_blocks), len(col_blocks)), dtype=int)

    for i, (r0, r1) in enumerate(row_blocks):
        for j, (c0, c1) in enumerate(col_blocks):
            panel = g[r0:r1, c0:c1]
            vals = panel[panel != 0]
            if vals.size == 0:
                continue
            color = int(vals[0])
            if np.array_equal(panel, np.rot90(panel, 2)):
                out[i, j] = color
            else:
                out[i, j] = 0

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    if len(nonzero_rows) == 0:
        return grid.copy()
    line_row = nonzero_rows[np.argmax(np.sum(grid[nonzero_rows] != 0, axis=1))]
    pattern = grid[:line_row]
    if pattern.size == 0:
        return grid.copy()
    h, w = pattern.shape
    out = np.zeros((h, w), dtype=grid.dtype)
    for i in range(h):
        out[i] = pattern[i % h]
    return out

