    h, w = grid.shape
    color = 5

    for r in range(h - 1):
        for c in range(w - 1):
            if grid[r, c] == color and grid[r, c + 1] == color and grid[r + 1, c] == color and grid[r + 1, c + 1] == color:
                if r - 1 >= 0 and c - 1 >= 0:
                    grid[r - 1, c - 1] = 1
                if r - 1 >= 0 and c + 2 < w:
                    grid[r - 1, c + 2] = 2
                if r + 2 < h and c - 1 >= 0:
                    grid[r + 2, c - 1] = 3
                if r + 2 < h and c + 2 < w:
                    grid[r + 2, c + 2] = 4
    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)
    best = None  # (area, r0, r1, c0, c1, color)

    def neighbors(r, c):
        if r > 0:
            yield r - 1, c
        if r + 1 < h:
            yield r + 1, c
        if c > 0:
            yield r, c - 1
        if c + 1 < w:
            yield r, c + 1

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 or visited[r, c]:
                continue
            color = grid[r, c]
            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for nx, ny in neighbors(x, y):
                    if not visited[nx, ny] and grid[nx, ny] != 0:
                        visited[nx, ny] = True
                        stack.append((nx, ny))
            rs = [p[0] for p in cells]
            cs = [p[1] for p in cells]
            r0, r1 = min(rs), max(rs)
            c0, c1 = min(cs), max(cs)
            area = (r1 - r0 + 1) * (c1 - c0 + 1)
            if best is None or area > best[0]:
                best = (area, r0, r1, c0, c1, color)

    if best is None:
        return np.zeros((0, 0), dtype=int)

    _, r0, r1, c0, c1, color = best
    sub = grid[r0:r1 + 1, c0:c1 + 1].copy()
    sub[sub == 0] = color
    return sub

