def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    if len(nonzero_rows) == 0:
        return grid

    base_top = nonzero_rows[0]
    base = grid[base_top:].copy()

    out = grid.copy()
    base_h = base.shape[0]

    for r in range(base_top):
        src_r = base_h - 1 - r
        if src_r < 0 or src_r >= base_h:
            continue
        for c in range(w):
            if out[r, c] == 0 and base[src_r, c] != 0:
                out[r, c] = base[src_r, c]

    return out

