def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    rows = [0, 1, g.shape[0] - 1]
    cols = [0, 1, g.shape[1] - 1]
    out = np.zeros((3, 3), dtype=int)
    for i, r in enumerate(rows):
        for j, c in enumerate(cols):
            out[i, j] = g[r, c]
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    def fill_color(inner_h, inner_w):
        if inner_h == 1 and inner_w == 1:
            return 6
        if inner_h == 2 and inner_w == 2:
            return 7
        if inner_h == 3 and inner_w == 3:
            return 8
        return None

    for r in range(h):
        for c in range(w):
            if grid[r, c] != 5 or visited[r, c]:
                continue

            # Find maximal rectangle of 5s starting at (r, c)
            rr = r
            while rr < h and grid[rr, c] == 5:
                rr += 1
            cc = c
            while cc < w and grid[r, cc] == 5:
                cc += 1

            # Determine rectangle bounds by checking contiguous 5 border
            bottom = r
            while bottom + 1 < h and grid[bottom + 1, c] == 5:
                bottom += 1
            right = c
            while right + 1 < w and grid[r, right + 1] == 5:
                right += 1

            # Verify rectangle border
            if bottom - r < 2 or right - c < 2:
                visited[r:bottom + 1, c:right + 1] = True
                continue

            # Check top and bottom borders
            if not np.all(grid[r, c:right + 1] == 5) or not np.all(grid[bottom, c:right + 1] == 5):
                visited[r:bottom + 1, c:right + 1] = True
                continue
            # Check left and right borders
            if not np.all(grid[r:bottom + 1, c] == 5) or not np.all(grid[r:bottom + 1, right] == 5):
                visited[r:bottom + 1, c:right + 1] = True
                continue

            inner_h = bottom - r - 1
            inner_w = right - c - 1
            color = fill_color(inner_h, inner_w)
            if color is not None:
                grid[r + 1:bottom, c + 1:right] = color

            visited[r:bottom + 1, c:right + 1] = True

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    sep = None
    for r in range(h):
        if np.all(grid[r] == 0):
            sep = r
            break

    if sep is None:
        return grid

    fg = 3
    top = grid[:sep].copy()
    bottom = grid[sep + 1:].copy()

    rows = min(top.shape[0], bottom.shape[0])
    cols = min(top.shape[1], bottom.shape[1])

    out = grid.copy()
    out[sep] = fg

    for r in range(rows):
        for c in range(cols):
            if top[r, c] != bottom[r, c]:
                out[r, c] = fg

    return out

