def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=False)
    n, m = g.shape
    out = np.zeros_like(g)

    seeds = np.argwhere(g != 0)
    if seeds.size == 0:
        return out

    for i in range(n):
        for j in range(m):
            best_color = 0
            best_dist = None
            for r, c in seeds:
                if r <= i and c <= j:
                    d = (i - r) + (j - c)
                    if best_dist is None or d < best_dist:
                        best_dist = d
                        best_color = g[r, c]
            if best_dist is not None:
                out[i, j] = best_color
    return out

