def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, dtype=int)
    h, w = grid.shape
    out = np.zeros((h, w), dtype=int)

    seeds = []
    for r in range(h):
        for c in range(w):
            v = grid[r, c]
            if v != 0:
                seeds.append((r, c, v))

    for sr, sc, color in seeds:
        for r in range(h):
            if r < sr:
                continue
            d = r - sr
            for c in range(w):
                if c >= sc and ((c - sc) % 2 == d % 2):
                    out[r, c] = color

    return out

