def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    vals, counts = np.unique(grid[grid != 0], return_counts=True)
    if len(vals) == 0:
        return grid
    color = vals[np.argmax(counts)]

    positions = np.argwhere(grid == color)
    if len(positions) == 0:
        return grid

    rows = np.unique(positions[:, 0])
    cols = np.unique(positions[:, 1])

    out = grid.copy()

    for r in rows:
        for c in cols:
            if out[r, c] == 0 or out[r, c] == color:
                out[r, c] = color

    return out

