def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the bottom-most non-empty row; the pattern is in the last two rows.
    non_empty_rows = np.where(np.any(grid != 0, axis=1))[0]
    if len(non_empty_rows) == 0:
        return grid
    bottom = non_empty_rows[-1]
    top = max(0, bottom - 1)

    # Determine the repeating motif width from the non-zero span in the bottom row.
    row = grid[bottom]
    nz = np.where(row != 0)[0]
    if len(nz) == 0:
        return grid
    motif_end = nz[-1] + 1

    # Find the smallest period that explains the non-zero structure in the bottom two rows.
    # Use the first occurrence of a repeated block as the motif.
    motif_width = motif_end
    for p in range(1, motif_end + 1):
        if motif_end % p != 0:
            continue
        ok = True
        for r in [top, bottom]:
            vals = grid[r, :motif_end]
            for i in range(motif_end):
                if vals[i] != vals[i % p]:
                    ok = False
                    break
            if not ok:
                break
        if ok:
            motif_width = p
            break

    # If no smaller period found, infer motif width from the first repeated non-zero block.
    if motif_width == motif_end:
        # Try to detect the first block length by looking for the first repeat of the left segment.
        for p in range(1, motif_end):
            if np.array_equal(grid[top:bottom+1, :p], grid[top:bottom+1, p:2*p]):
                motif_width = p
                break

    # Repeat the motif across the full width.
    out = np.zeros_like(grid)
    motif = grid[top:bottom+1, :motif_width]
    for start in range(0, w, motif_width):
        end = min(w, start + motif_width)
        out[top:bottom+1, start:end] = motif[:, :end-start]

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    def neighbors(r, c):
        if r > 0:
            yield r - 1, c
        if r + 1 < h:
            yield r + 1, c
        if c > 0:
            yield r, c - 1
        if c + 1 < w:
            yield r, c + 1

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                cells = []
                min_r = max_r = r
                min_c = max_c = c

                while stack:
                    cr, cc = stack.pop()
                    cells.append((cr, cc))
                    if cr < min_r: min_r = cr
                    if cr > max_r: max_r = cr
                    if cc < min_c: min_c = cc
                    if cc > max_c: max_c = cc
                    for nr, nc in neighbors(cr, cc):
                        if grid[nr, nc] == 0 and not visited[nr, nc]:
                            visited[nr, nc] = True
                            stack.append((nr, nc))

                bh = max_r - min_r + 1
                bw = max_c - min_c + 1
                if bh == 2 and bw == 2:
                    color = 1
                elif (bh == 1 and bw == 2) or (bh == 2 and bw == 1):
                    color = 2
                elif bh == 1 and bw == 1:
                    color = 3
                else:
                    color = 0

                for cr, cc in cells:
                    grid[cr, cc] = color

    return grid

