def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    sep_rows = np.where(np.all(grid == 5, axis=1))[0]
    if len(sep_rows) == 0:
        return grid.copy()
    sep = sep_rows[0]
    top = grid[:sep]
    bottom = grid[sep + 1:]
    return np.where(bottom != 0, bottom, top)

