import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    color = int(np.max(input_grid))
    ys, xs = np.where(input_grid == color)
    if len(ys) == 0:
        return np.zeros((0, 0), dtype=int)

    out = np.zeros((input_grid.shape[0] * 2, input_grid.shape[1] * 2), dtype=int)
    for y, x in zip(ys, xs):
        out[2 * y:2 * y + 2, 2 * x:2 * x + 2] = color

    rows = np.where(np.any(out != 0, axis=1))[0]
    cols = np.where(np.any(out != 0, axis=0))[0]
    return out[rows.min():rows.max() + 1, cols.min():cols.max() + 1]

