    tiled = np.tile(g, (2, 2))
    return np.where(tiled == 0, 8, tiled)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    # Extract the non-zero 2x2 blocks at odd rows/cols (1-indexed pattern)
    counts = {}
    for r in range(1, h, 2):
        for c in range(1, w, 2):
            block = g[r:r+2, c:c+2]
            if block.size == 0:
                continue
            vals = block[block != 0]
            if vals.size == 0:
                continue
            # Each block is uniform non-zero in these tasks
            color = int(vals[0])
            counts[color] = counts.get(color, 0) + 1

    if not counts:
        return np.zeros((3, 1), dtype=int)

    # Take the three colors with the smallest positive counts,
    # ordered from most frequent to least frequent among those three.
    items = sorted(counts.items(), key=lambda kv: (kv[1], kv[0]))
    selected = items[:3]
    selected = sorted(selected, key=lambda kv: (-kv[1], kv[0]))

    out = np.array([[color] for color, _ in selected], dtype=int)
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    for r in range(h - 1):
        for c in range(w - 1):
            block = grid[r:r+2, c:c+2]
            if np.all(block != 0):
                if not np.all(block == block[0, 0]):
                    grid[r:r+2, c:c+2] = 3
    return grid
